/* ---------- 3) شارة ديما بصفحة الدفع ---------- */
(function () {
  function onEcwidReady(cb) {
    if (window.Ecwid && window.Ecwid.OnAPILoaded) { Ecwid.OnAPILoaded.add(cb); }
    else { setTimeout(function () { onEcwidReady(cb); }, 300); }
  }
  onEcwidReady(function () {
    Ecwid.OnPageLoaded.add(function (page) {
      if (page.type === "CHECKOUT_PAYMENT_DETAILS" || page.type === "ORDER_CONFIRMATION" || page.type === "CHECKOUT") {
        setTimeout(addDeemaInstallmentInfo, 500);
      }
    });
  });
  function addDeemaInstallmentInfo() {
    var items = document.querySelectorAll(".ec-radiogroup__item");
    items.forEach(function (item) {
      var text = item.textContent || "";
      if (text.toLowerCase().indexOf("deema") === -1) return;
      if (item.querySelector(".sc-deema-info")) return;
      var info = document.createElement("div");
      info.className = "sc-deema-info";
      info.style.cssText = "margin-top:8px;padding:8px 10px;border-radius:6px;background:#f5f5f5;font-size:12px;color:#333;direction:rtl;display:flex;align-items:center;gap:8px;";
      info.innerHTML = '<span>قسّط فاتورتك على 2، 3، أو 4 دفعات بدون فوائد مع ديما</span>';
      item.appendChild(info);
    });
  }
})();

/* ---------- 4) حل تراكب نص التوجيه فوق القيمة المُدخلة (حقل التاريخ وغيره) ---------- */
(function () {
  function hideFilledPlaceholders() {
    var fields = document.querySelectorAll(".ec-form .form-control__text, .ec-form input");
    fields.forEach(function (input) {
      var wrapper = input.closest(".form-control, .ec-form__row");
      if (!wrapper) return;
      var placeholder = wrapper.querySelector(".form-control__placeholder, .form-control__placeholder-inner");
      if (!placeholder) return;
      placeholder.style.display = (input.value && input.value.trim() !== "") ? "none" : "block";
    });
  }
  function onEcwidReady2(cb) {
    if (window.Ecwid && window.Ecwid.OnAPILoaded) { Ecwid.OnAPILoaded.add(cb); }
    else { setTimeout(function () { onEcwidReady2(cb); }, 300); }
  }
  onEcwidReady2(function () {
    Ecwid.OnPageLoaded.add(function () {
      setTimeout(hideFilledPlaceholders, 400);
      document.addEventListener("input", hideFilledPlaceholders, true);
      document.addEventListener("change", hideFilledPlaceholders, true);
    });
  });
})();

/* ---------- 5) شارة ديما + عداد كمية للموبايل بصفحة المنتج (وضع تجربة: منتج Poseidon Pro) ---------- */
(function () {
  // تعرّف على صفحة المنتج مباشرة من رابط الصفحة (أضمن من الاعتماد على توقيت حدث Ecwid فقط)
  var TEST_URL_SLUG = "poseidon-pro"; // غيّرها إلى null لتفعيلها على كل المنتجات

  function isTestProductPage() {
    if (!TEST_URL_SLUG) return true;
    return location.pathname.toLowerCase().indexOf(TEST_URL_SLUG) !== -1;
  }

  function tryRun() {
    if (!isTestProductPage()) return;
    addDeemaProductBadge();
    addQuantityStepper();
  }

  // فحص فوري + فحص متكرر كل ثانية (يغطي التحميل الأول والتنقل بين المنتجات بدون انتظار حدث معيّن)
  tryRun();
  setInterval(tryRun, 1000);

  function addDeemaProductBadge() {
    if (document.getElementById("sc-deema-badge")) return; // موجودة أصلاً، لا داعي لإعادة الإضافة
    var priceEl = document.querySelector(
      ".product-details__product-price, .details-product-purchase__price, .product-details__price, .ecwid-productBrowser-price"
    );
    if (!priceEl) return;
    var priceText = priceEl.textContent.replace(/[^\d.]/g, "");
    var price = parseFloat(priceText);
    if (!price || isNaN(price)) return;
    var MIN_PRICE_FOR_BADGE = 7;
    if (price < MIN_PRICE_FOR_BADGE) return;
    var lowestPerPayment = (price / 4).toFixed(3);
    var badge = document.createElement("div");
    badge.id = "sc-deema-badge";
    badge.style.cssText =
      "margin:8px 0;padding:8px 10px;border:1px solid #eee;border-radius:8px;" +
      "font-size:13px;line-height:1.5;display:flex;align-items:center;gap:6px;" +
      "background:#fafafa;direction:rtl;";
    badge.innerHTML =
      '<span style="font-weight:600;">قسّطها مع ديما</span>' +
      '<span>— ابتداءً من ' + lowestPerPayment + ' د.ك / 4 دفعات</span>';
    priceEl.insertAdjacentElement("afterend", badge);
  }

  function addQuantityStepper() {
    if (window.innerWidth > 767) return;
    var qtyInput = document.querySelector(
      'input[name="quantity"], .details-product-purchase__quantity input, .form-control__quantity'
    );
    if (!qtyInput) return;
    if (qtyInput.dataset.scStepperAdded) return;
    qtyInput.dataset.scStepperAdded = "true";
    var wrapper = document.createElement("div");
    wrapper.style.cssText = "display:flex;align-items:center;gap:8px;";
    var minusBtn = document.createElement("button");
    minusBtn.type = "button";
    minusBtn.textContent = "−";
    minusBtn.style.cssText =
      "width:36px;height:36px;font-size:18px;border:1px solid #ccc;border-radius:6px;background:#fff;";
    var plusBtn = document.createElement("button");
    plusBtn.type = "button";
    plusBtn.textContent = "+";
    plusBtn.style.cssText = minusBtn.style.cssText;
    qtyInput.style.cssText += "text-align:center;width:50px;";
    qtyInput.parentNode.insertBefore(wrapper, qtyInput);
    wrapper.appendChild(minusBtn);
    wrapper.appendChild(qtyInput);
    wrapper.appendChild(plusBtn);
    function fireChange() {
      qtyInput.dispatchEvent(new Event("change", { bubbles: true }));
      qtyInput.dispatchEvent(new Event("input", { bubbles: true }));
    }
    minusBtn.addEventListener("click", function () {
      var val = parseInt(qtyInput.value, 10) || 1;
      if (val > 1) qtyInput.value = val - 1;
      fireChange();
    });
    plusBtn.addEventListener("click", function () {
      var val = parseInt(qtyInput.value, 10) || 1;
      qtyInput.value = val + 1;
      fireChange();
    });
  }
})();
